// 🧠 Búsqueda Profunda de Texto (WhatsApp/Telegram)
const item = $input.first().json;
const body = item.body || item;
let platform = "";
let sender_contact = "";
let extracted_text = "";

// ⚙️ 1. Identificación de WhatsApp / Whapi / Bot Directo
const isWhatsApp = !!(body.platform === "whatsApp" || body.key || body.whapi_cloud || item.platform === "whatsApp" || (item.message?._session && !item.message?.chat?.type));
platform = isWhatsApp ? "WhatsApp" : "Telegram";

// 🔍 ESCANEO PROFUNDO DE TEXTO
if (isWhatsApp) {
    sender_contact = body.from || (body.key ? body.key.remoteJid : "") || body.pushName || item.sender || "";
    const t = [];
    if (typeof body === 'string') t.push(body);
    if (body.text) t.push(typeof body.text === 'string' ? body.text : (body.text.body || ""));
    if (body.body) t.push(typeof body.body === 'string' ? body.body : (body.body.text || ""));
    if (body.caption) t.push(body.caption);
    extracted_text = t.filter(x => x).join(" | ");
} else {
    const msg = item.message || item.channel_post || {};
    extracted_text = item.text || body.text || msg.text || msg.caption || "";
    sender_contact = item.sender || (msg.from?.username ? `@${msg.from.username}` : "");
}

// 🧹 2. Limpieza y Filtro Anti-429 (100 caracteres)
const clean_text = String(extracted_text || "").trim();
const isSystemTrash = !!(item.message?.voice || item.message?.sticker || item.message?.document);
const isTooShort = clean_text.length < 100;

const looksValuable = !isSystemTrash && !isTooShort;

return {
  platform: platform,
  sender_contact: String(sender_contact).trim(),
  extracted_text: clean_text,
  texto_limpio: clean_text,
  looksValuable: looksValuable,
  trash_early: !looksValuable,
  media_type: looksValuable ? "text" : "junk"
};

const store = $getWorkflowStaticData('global');
if (!store.seen) store.seen = {};
const now = Date.now();
const ttl = 60 * 60 * 1000; // 1 hour
for (const k in store.seen) {
  if (now - store.seen[k] > ttl) delete store.seen[k];
}
const raw = String($json.extracted_text || '').toLowerCase().trim().replace(/[^a-z0-9\u00C0-\u024F\u0400-\u04FF]/gi, '');
if (raw.length < 15) return items;
let hash = 0;
for (let i = 0; i < raw.length; i++) {
  hash = ((hash << 5) - hash) + raw.charCodeAt(i);
  hash |= 0;
}
const key = String(hash);
if (store.seen[key]) return [];
store.seen[key] = now;
return items;

// 🧠 Lead validation with ANTI-SPAM and Link control (v5)
const items = $input.all();
const bannedKeywords = [
  'crypto', 'binance', 'forex', 'casino', 'stake', 'signals', 'trading', 'pump', 'usdt', 
  'virtual', 'hombre busca', 'pasivo', 'pasivos', 'hombre generoso', 'conoceré',
  'man looks', 'man seeking', 'man seeks', 'generous man', 'passive',
  'homem procura', 'виртуально', 'мужчина ищет', 'щедрый мужчина',
  'teocar', 'veiculo', 'carro', 'automoveis', 'aluguel', 'venda', 'vender'
];
const spamSectors = ['cocina', 'cocinero', 'camarero', 'repartidor', 'limpieza', 'obra', 'pintor', 'conductor', 'almacén', 'ayudante', 'restaurante'];
// 🚨 Diccionario Ampliado del Sector
const industryKeywords = [
  'modelo', 'escort', 'plaza', 'club', 'viaje', 'booking', 'agency', 'agencia', 'casting', 'acompañante', 'masaje', 'erotico', 'room', 
  'vaga', 'quarto', 'trans', 'travesti', 'reunion', 'reunión', 'meeting', 'cita', 'encontro', 'verificacion', 'verificación', 'pago', 'vip'
];

const out = [];
for (const item of items) {
  const text = (item.json.texto_limpio || '').toLowerCase();
  const hasBanned = bannedKeywords.some(k => text.includes(k));
  const hasSpamSector = spamSectors.some(k => text.includes(k));
  const hasIndustry = industryKeywords.some(k => text.includes(k));
  const linkCount = (text.match(/https?:|t\.me|wa\.me/g) || []).length;

  const isLinkSpam = linkCount >= 2 && !hasIndustry;

  // UMBRAL DE CALIDAD: Ahora permite textos más cortos si contienen palabras del sector
  let isValuable = !hasBanned && !hasSpamSector && !isLinkSpam && (hasIndustry || text.length > 100);

  if (item.json.trash_early) isValuable = false;

  out.push({
    json: {
      ...item.json,
      looksValuable: isValuable,
      trash: (hasBanned || hasSpamSector || isLinkSpam || item.json.trash_early) ? true : undefined,
      summary: isLinkSpam ? `[DESCARTADO: Spam de enlaces]` : (hasSpamSector ? `[DESCARTADO: Sector no relevante]` : (hasBanned ? `[AUTO-FILTERED: Banned phrase]` : undefined)),
      prefilter_v5: true
    }
  });
}
return out;

// 🧠 Centralizer code for different platforms and formats
const items = $input.all();
return items.map(i => ({
  json: {
    ...i.json,
    balanced_at: new Date().toISOString(),
    source_id: i.json.platform || "Unknown"
  }
}));

let content;
try {
  const rawAI = $input.first().json.content.parts[0].text;
  content = JSON.parse(rawAI.replace(/```json|```/g, '').trim());

  const meta = $node["Extract Metadata1"].json;
  const originalText = (meta.extracted_text || "");
  const rawInput = originalText.toUpperCase();

  const isPlazaLongTerm = /HABITACION|QUARTO|RECLUTAM|RECRUIT|EMPLEO|TRABAJO|TRABALHO|JOB|WORK|VAGA|ESTANCIA|DAYS|DIAS|WEEKL|SEMANAL/.test(rawInput);
  const isDemand = /BUSCO|NECESITO|SOLICITO|WANTED|LOOKING|REQUIRED|NEED|ИЩУ|SE NECESITA|QUIEN|ALGUIEN|CLIENTE/.test(rawInput);
  const isHourly = /HORA|HOURS|HOUR|2H|3H|4H|5H|6H|EXPR|MVR|TIME/.test(rawInput);
  const isShortDuration = /(2|3|4|5|6) HORAS|UNA CITA|FINALIZACIÓN|MBR/.test(rawInput);

  if (isPlazaLongTerm) content.category = 'plaza';
  else if (isDemand || isHourly || isShortDuration) content.category = 'evento';
  else if (!['plaza', 'evento', 'escorts'].includes(content.category)) content.category = 'escorts';

  if (content.trash !== false) { 
    if (meta.trash_early || originalText.length < 5) content.trash = true;
  }

} catch (e) {
  content = { trash: true, error_parse: true };
}

const metaFinal = $node["Extract Metadata1"].json;
return [{ json: { ...metaFinal, ...content, raw_ai_output: content } }];

